import{_ as a,o as t,c as i,ag as r}from"./chunks/framework.DEqXEGcv.js";const u=JSON.parse('{"title":"更多应用","description":"","frontmatter":{},"headers":[],"relativePath":"zh/docs/guide/apps.md","filePath":"zh/docs/guide/apps.md"}'),o={name:"zh/docs/guide/apps.md"};function s(n,l,e,g,h,p){return t(),i("div",null,[...l[0]||(l[0]=[r('<h1 id="更多应用" tabindex="-1">更多应用 <a class="header-anchor" href="#更多应用" aria-label="Permalink to &quot;更多应用&quot;">​</a></h1><p>除了核心的文件管理、Docker、终端外，RDE 还内置了丰富的桌面应用。</p><h2 id="🎵-音乐播放器" tabindex="-1">🎵 音乐播放器 <a class="header-anchor" href="#🎵-音乐播放器" aria-label="Permalink to &quot;🎵 音乐播放器&quot;">​</a></h2><p>功能完整的桌面音乐应用：</p><ul><li><strong>多种显示模式</strong>：迷你模式、窗口模式、壁纸模式</li><li><strong>歌词显示</strong>：支持 LRC 歌词同步显示</li><li><strong>音频可视化</strong>：频谱柱、环形、万花筒等多种可视化效果</li><li><strong>播放列表</strong>：创建和管理多个播放列表</li><li><strong>支持格式</strong>：MP3, FLAC, WAV, OGG, AAC 等</li></ul><h2 id="🎬-视频播放器" tabindex="-1">🎬 视频播放器 <a class="header-anchor" href="#🎬-视频播放器" aria-label="Permalink to &quot;🎬 视频播放器&quot;">​</a></h2><p>多格式桌面视频播放器：</p><ul><li><strong>广泛格式支持</strong>：MP4, MKV, AVI, WebM 等</li><li><strong>实时转码</strong>：ffmpeg HLS 转码，浏览器不支持的格式也能播放</li><li><strong>字幕支持</strong>：自动加载同名字幕文件</li><li><strong>播放记忆</strong>：记住上次播放位置</li><li><strong>倍速播放</strong>：0.5x ~ 3x 播放速度</li><li><strong>画中画</strong>：浮窗模式播放</li><li><strong>文件管理器集成</strong>：双击视频文件直接播放</li></ul><h2 id="📸-相册" tabindex="-1">📸 相册 <a class="header-anchor" href="#📸-相册" aria-label="Permalink to &quot;📸 相册&quot;">​</a></h2><p>类群晖/Immich 的索引式相册系统：</p><ul><li><strong>自动索引</strong>：扫描指定目录的照片</li><li><strong>元数据提取</strong>：EXIF/GPS 信息读取</li><li><strong>缩略图生成</strong>：自动生成多尺寸缩略图</li><li><strong>相册管理</strong>：创建和整理相册</li><li><strong>时间线视图</strong>：按日期浏览照片</li></ul><h2 id="🎮-复古游戏" tabindex="-1">🎮 复古游戏 <a class="header-anchor" href="#🎮-复古游戏" aria-label="Permalink to &quot;🎮 复古游戏&quot;">​</a></h2><p>基于 EmulatorJS（WebAssembly）的纯前端复古游戏模拟器：</p><ul><li><strong>支持平台</strong>：NES, SNES, GBA, GBC, N64, PS1, NDS, Sega MD 等 12 个经典平台</li><li><strong>ROM 管理</strong>：上传和管理游戏 ROM 文件</li><li><strong>手柄支持</strong>：连接 USB/蓝牙手柄游玩</li><li><strong>存档管理</strong>：随时存档/读档</li><li><strong>纯前端运行</strong>：无需额外后端服务</li></ul><h2 id="📦-flatpak-应用" tabindex="-1">📦 Flatpak 应用 <a class="header-anchor" href="#📦-flatpak-应用" aria-label="Permalink to &quot;📦 Flatpak 应用&quot;">​</a></h2><p>在浏览器中运行 Linux 桌面 GUI 应用：</p><ul><li>通过 KasmVNC 实现浏览器内 GUI 渲染</li><li>Flatpak 作为应用来源，跨发行版通用</li><li>支持多会话并发</li><li>应用安装/卸载管理</li></ul><h2 id="📊-系统监控" tabindex="-1">📊 系统监控 <a class="header-anchor" href="#📊-系统监控" aria-label="Permalink to &quot;📊 系统监控&quot;">​</a></h2><p>实时系统监控仪表盘：</p><ul><li>CPU 使用率和负载</li><li>内存使用情况</li><li>磁盘空间和 I/O</li><li>网络流量</li></ul>',20)])])}const c=a(o,[["render",s]]);export{u as __pageData,c as default};
